# regal ignore:directory-package-mismatch
package armo_builtins

import rego.v1

################################################################################
# Rules
deny contains msga if {
	start_of_path := "spec"
	pod := input[_]
	pod.kind == "Pod"
	container := pod.spec.containers[i]

	run_as_user_fixpath := evaluate_workload_run_as_user(container, pod, start_of_path)
	run_as_group_fixpath := evaluate_workload_run_as_group(container, pod, start_of_path)
	all_fixpaths := array.concat(run_as_user_fixpath, run_as_group_fixpath)
	count(all_fixpaths) > 0
	fixPaths := get_fixed_paths(all_fixpaths, i)

	msga := {
		"alertMessage": sprintf("container: %v in pod: %v  may run as root", [container.name, pod.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"reviewPaths": [],
		"failedPaths": [],
		"fixPaths": fixPaths,
		"alertObject": {"k8sApiObjects": [pod]},
	}
}

deny contains msga if {
	start_of_path := "spec.template.spec"
	spec_template_spec_patterns := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	wl := input[_]
	spec_template_spec_patterns[wl.kind]
	container := wl.spec.template.spec.containers[i]

	run_as_user_fixpath := evaluate_workload_run_as_user(container, wl.spec.template, start_of_path)
	run_as_group_fixpath := evaluate_workload_run_as_group(container, wl.spec.template, start_of_path)
	all_fixpaths := array.concat(run_as_user_fixpath, run_as_group_fixpath)
	count(all_fixpaths) > 0
	fixPaths := get_fixed_paths(all_fixpaths, i)

	msga := {
		"alertMessage": sprintf("container: %v in %v: %v may run as root", [container.name, wl.kind, wl.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"reviewPaths": [],
		"failedPaths": [],
		"fixPaths": fixPaths,
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

# Fails if cronjob has a container configured to run as root
deny contains msga if {
	start_of_path := "spec.jobTemplate.spec.template.spec"
	wl := input[_]
	wl.kind == "CronJob"
	container = wl.spec.jobTemplate.spec.template.spec.containers[i]

	run_as_user_fixpath := evaluate_workload_run_as_user(container, wl.spec.jobTemplate.spec.template, start_of_path)
	run_as_group_fixpath := evaluate_workload_run_as_group(container, wl.spec.jobTemplate.spec.template, start_of_path)
	all_fixpaths := array.concat(run_as_user_fixpath, run_as_group_fixpath)
	count(all_fixpaths) > 0
	fixPaths := get_fixed_paths(all_fixpaths, i)

	msga := {
		"alertMessage": sprintf("container: %v in %v: %v  may run as root", [container.name, wl.kind, wl.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"reviewPaths": [],
		"failedPaths": [],
		"fixPaths": fixPaths,
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

get_fixed_paths(all_fixpaths, i) := [{"path": replace(all_fixpaths[0].path, "container_ndx", format_int(i, 10)), "value": all_fixpaths[0].value}, {"path": replace(all_fixpaths[1].path, "container_ndx", format_int(i, 10)), "value": all_fixpaths[1].value}] if {
	count(all_fixpaths) == 2
} else := [{"path": replace(all_fixpaths[0].path, "container_ndx", format_int(i, 10)), "value": all_fixpaths[0].value}]

#################################################################################
# Workload evaluation

# if runAsUser is set to 0 and runAsNonRoot is set to false/ not set - suggest to set runAsUser to 1000
# if runAsUser is not set and runAsNonRoot is set to false/ not set - suggest to set runAsNonRoot to true
# all checks are both on the pod and the container level
evaluate_workload_run_as_user(container, pod, start_of_path) := fixPath if {
	runAsNonRootValue := get_run_as_non_root_value(container, pod, start_of_path)
	runAsNonRootValue.value == false

	runAsUserValue := get_run_as_user_value(container, pod, start_of_path)
	runAsUserValue.value == 0

	alertInfo := choose_first_if_defined(runAsUserValue, runAsNonRootValue)
	fixPath := alertInfo.fixPath
} else := []

# if runAsGroup is set to 0/ not set - suggest to set runAsGroup to 1000
# all checks are both on the pod and the container level
evaluate_workload_run_as_group(container, pod, start_of_path) := fixPath if {
	runAsGroupValue := get_run_as_group_value(container, pod, start_of_path)
	runAsGroupValue.value == 0

	fixPath := runAsGroupValue.fixPath
} else := []

#################################################################################
# Value resolution functions

get_run_as_non_root_value(container, pod, start_of_path) := runAsNonRoot if {
	runAsNonRoot := {"value": container.securityContext.runAsNonRoot, "fixPath": [{"path": sprintf("%v.containers[container_ndx].securityContext.runAsNonRoot", [start_of_path]), "value": "true"}], "defined": true}
} else := runAsNonRoot if {
	runAsNonRoot := {"value": pod.spec.securityContext.runAsNonRoot, "fixPath": [{"path": sprintf("%v.containers[container_ndx].securityContext.runAsNonRoot", [start_of_path]), "value": "true"}], "defined": true}
} else := {"value": false, "fixPath": [{"path": sprintf("%v.containers[container_ndx].securityContext.runAsNonRoot", [start_of_path]), "value": "true"}], "defined": false}

get_run_as_user_value(container, pod, start_of_path) := runAsUser if {
	path := sprintf("%v.containers[container_ndx].securityContext.runAsUser", [start_of_path])
	runAsUser := {"value": container.securityContext.runAsUser, "fixPath": [{"path": path, "value": "1000"}], "defined": true}
} else := runAsUser if {
	path := sprintf("%v.securityContext.runAsUser", [start_of_path])
	runAsUser := {"value": pod.spec.securityContext.runAsUser, "fixPath": [{"path": path, "value": "1000"}], "defined": true}
} else := {
	"value": 0, "fixPath": [{"path": sprintf("%v.containers[container_ndx].securityContext.runAsNonRoot", [start_of_path]), "value": "true"}],
	"defined": false,
}

get_run_as_group_value(container, pod, start_of_path) := runAsGroup if {
	path := sprintf("%v.containers[container_ndx].securityContext.runAsGroup", [start_of_path])
	runAsGroup := {"value": container.securityContext.runAsGroup, "fixPath": [{"path": path, "value": "1000"}], "defined": true}
} else := runAsGroup if {
	path := sprintf("%v.securityContext.runAsGroup", [start_of_path])
	runAsGroup := {"value": pod.spec.securityContext.runAsGroup, "fixPath": [{"path": path, "value": "1000"}], "defined": true}
} else := {
	"value": 0, "fixPath": [{"path": sprintf("%v.containers[container_ndx].securityContext.runAsGroup", [start_of_path]), "value": "1000"}],
	"defined": false,
}

choose_first_if_defined(l1, l2) := l1 if {
	l1.defined
} else := l2

# regal ignore:directory-package-mismatch
package armo_builtins

import rego.v1

# Fails if pods has container with mutable filesystem
deny contains msga if {
	start_of_path := "spec."
	pod := input[_]
	pod.kind == "Pod"
	container := pod.spec.containers[i]
	is_mutable_filesystem(container)
	fixPath = {"path": sprintf("%vcontainers[%d].securityContext.readOnlyRootFilesystem", [start_of_path, i]), "value": "true"}
	msga := {
		"alertMessage": sprintf("container: %v in pod: %v  has  mutable filesystem", [container.name, pod.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"failedPaths": [],
		"fixPaths": [fixPath],
		"alertObject": {"k8sApiObjects": [pod]},
	}
}

# Fails if workload has  container with mutable filesystem
deny contains msga if {
	spec_template_spec_patterns := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	start_of_path := "spec.template.spec."
	wl := input[_]
	spec_template_spec_patterns[wl.kind]
	container := wl.spec.template.spec.containers[i]
	is_mutable_filesystem(container)
	fixPath = {"path": sprintf("%vcontainers[%d].securityContext.readOnlyRootFilesystem", [start_of_path, i]), "value": "true"}
	msga := {
		"alertMessage": sprintf("container :%v in %v: %v has  mutable filesystem", [container.name, wl.kind, wl.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"failedPaths": [],
		"fixPaths": [fixPath],
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

# Fails if cronjob has  container with mutable filesystem
deny contains msga if {
	start_of_path := "spec.jobTemplate.spec.template.spec."
	wl := input[_]
	wl.kind == "CronJob"
	container = wl.spec.jobTemplate.spec.template.spec.containers[i]
	is_mutable_filesystem(container)
	fixPath = {"path": sprintf("%vcontainers[%d].securityContext.readOnlyRootFilesystem", [start_of_path, i]), "value": "true"}

	msga := {
		"alertMessage": sprintf("container :%v in %v: %v has mutable filesystem", [container.name, wl.kind, wl.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"failedPaths": [],
		"fixPaths": [fixPath],
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

# Default of readOnlyRootFilesystem is false. This field is only in container spec and not pod spec
is_mutable_filesystem(container) if {
	container.securityContext.readOnlyRootFilesystem == false
}

is_mutable_filesystem(container) if {
	not container.securityContext.readOnlyRootFilesystem == false
	not container.securityContext.readOnlyRootFilesystem == true
}

# regal ignore:directory-package-mismatch
package armo_builtins

import rego.v1

# This rule honours Kubernetes precedence: pod.spec.automountServiceAccountToken
# overrides serviceAccount.automountServiceAccountToken. It alerts only on
# workloads that will actually mount a token (pod-level true, or pod-level
# unset with an SA that does not explicitly disable).

# POD
deny contains msga if {
	start_of_path := "spec."
	pod := input[_]
	pod.kind == "Pod"

	wl_namespace := pod_namespace(pod)
	result := is_sa_auto_mounted(pod.spec, start_of_path, wl_namespace)
	failed_path := get_failed_path(result)
	fixed_path := get_fixed_path(result)

	msga := {
		"alertMessage": sprintf("Pod: %v in the following namespace: %v mounts service account tokens by default", [pod.metadata.name, wl_namespace]),
		"alertScore": 9,
		"packagename": "armo_builtins",
		"fixPaths": fixed_path,
		"failedPaths": failed_path,
		"alertObject": {"k8sApiObjects": [pod]},
	}
}

# WORKLOADS: Deployment / ReplicaSet / DaemonSet / StatefulSet / Job
deny contains msga if {
	start_of_path := "spec.template.spec."
	spec_template_spec_patterns := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	wl := input[_]
	spec_template_spec_patterns[wl.kind]

	wl_namespace := pod_namespace(wl)
	result := is_sa_auto_mounted(wl.spec.template.spec, start_of_path, wl_namespace)
	failed_path := get_failed_path(result)
	fixed_path := get_fixed_path(result)

	msga := {
		"alertMessage": sprintf("%v: %v in the following namespace: %v mounts service account tokens by default", [wl.kind, wl.metadata.name, wl_namespace]),
		"alertScore": 7,
		"packagename": "armo_builtins",
		"fixPaths": fixed_path,
		"failedPaths": failed_path,
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

# CRONJOB
deny contains msga if {
	start_of_path := "spec.jobTemplate.spec.template.spec."
	wl := input[_]
	wl.kind == "CronJob"

	wl_namespace := pod_namespace(wl)
	result := is_sa_auto_mounted(wl.spec.jobTemplate.spec.template.spec, start_of_path, wl_namespace)
	failed_path := get_failed_path(result)
	fixed_path := get_fixed_path(result)

	msga := {
		"alertMessage": sprintf("%v: %v in the following namespace: %v mounts service account tokens by default", [wl.kind, wl.metadata.name, wl_namespace]),
		"alertScore": 7,
		"packagename": "armo_builtins",
		"fixPaths": fixed_path,
		"failedPaths": failed_path,
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

# ----- decision helpers -----

# Branch 1: pod spec explicitly sets automountServiceAccountToken: true.
# Pod-level wins over SA, so this always mounts. Fix by setting the pod
# field to false - deleting it is unsafe because it falls back to the SA,
# which may also enable auto-mount.
is_sa_auto_mounted(spec, start_of_path, wl_namespace) := [failed_path, fix_path] if {
	spec.automountServiceAccountToken == true

	failed_path := sprintf("%vautomountServiceAccountToken", [start_of_path])
	fix_path := {"path": sprintf("%vautomountServiceAccountToken", [start_of_path]), "value": "false"}
}

# Branch 2: pod spec does not set automountServiceAccountToken, and the
# referenced SA exists and does not explicitly disable auto-mount. Token
# will mount by default. Fix by setting pod-level to false.
is_sa_auto_mounted(spec, start_of_path, wl_namespace) := [failed_path, fix_path] if {
	failed_path := ""
	fix_path := {"path": sprintf("%vautomountServiceAccountToken", [start_of_path]), "value": "false"}
	not spec.automountServiceAccountToken == false
	not spec.automountServiceAccountToken == true

	sa := input[_]
	sa.kind == "ServiceAccount"
	is_same_sa(spec, sa.metadata.name)
	is_same_namespace(sa.metadata.namespace, wl_namespace)
	not sa.automountServiceAccountToken == false

}

# Branch 3: pod spec does not set automountServiceAccountToken, and no
# matching SA is in the input (YAML scan, or SA not scanned). Kubernetes
# default is to mount, so flag it.
is_sa_auto_mounted(spec, start_of_path, wl_namespace) := [failed_path, fix_path] if {
	not spec.automountServiceAccountToken == false
	not spec.automountServiceAccountToken == true

	not matching_sa_exists(spec, wl_namespace)

	fix_path := {"path": sprintf("%vautomountServiceAccountToken", [start_of_path]), "value": "false"}
	failed_path := ""
}

# No branch when spec.automountServiceAccountToken == false: pod-level
# disable wins over any SA setting, so no deny.

matching_sa_exists(spec, wl_namespace) if {
	sa := input[_]
	sa.kind == "ServiceAccount"
	is_same_sa(spec, sa.metadata.name)
	is_same_namespace(sa.metadata.namespace, wl_namespace)
}

get_failed_path(paths) := [paths[0]] if {
	paths[0] != ""
} else := []

get_fixed_path(paths) := [paths[1]] if {
	paths[1] != ""
} else := []

# ----- matching helpers -----

pod_namespace(obj) := ns if {
	ns := obj.metadata.namespace
} else := "default"

is_same_sa(spec, serviceAccountName) if {
	spec.serviceAccountName == serviceAccountName
}

is_same_sa(spec, serviceAccountName) if {
	not spec.serviceAccountName
	serviceAccountName == "default"
}

is_same_namespace(ns1, ns2) if {
	ns1 == ns2
}

is_same_namespace(ns1, ns2) if {
	not ns1
	ns2 == "default"
}

is_same_namespace(ns1, ns2) if {
	not ns2
	ns1 == "default"
}

# regal ignore:directory-package-mismatch  
package armo_builtins

import rego.v1

# Check if encryption in etcd in enabled for AKS
deny contains msga if {
	cluster_config := input[_]
	cluster_config.apiVersion == "management.azure.com/v1"
	cluster_config.kind == "ClusterDescribe"
	cluster_config.metadata.provider == "aks"
	config = cluster_config.data

	not isEncryptedAKS(config)

	msga := {
		"alertMessage": "etcd/secret encryption is not enabled",
		"alertScore": 3,
		"packagename": "armo_builtins",
		"failedPaths": [],
		"fixPaths": [],
		"fixCommand": "az aks nodepool add --name hostencrypt --cluster-name <myAKSCluster> --resource-group <myResourceGroup> -s Standard_DS2_v2 -l <myRegion> --enable-encryption-at-host",
		"alertObject": {"externalObjects": cluster_config},
	}
}

# Check if encryption in etcd is enabled for EKS
deny contains msga if {
	cluster_config := input[_]
	cluster_config.apiVersion == "eks.amazonaws.com/v1"
	cluster_config.kind == "ClusterDescribe"
	cluster_config.metadata.provider == "eks"
	config := cluster_config.data

	not is_encrypted_EKS(config)

	msga := {
		"alertMessage": "etcd/secret encryption is not enabled",
		"alertScore": 3,
		"packagename": "armo_builtins",
		"failedPaths": [],
		"fixPaths": [],
		"fixCommand": "eksctl utils enable-secrets-encryption --cluster=<cluster> --key-arn=arn:aws:kms:<cluster_region>:<account>:key/<key> --region=<region>",
		"alertObject": {
			"k8sApiObjects": [],
			"externalObjects": cluster_config,
		},
	}
}

# Check if encryption in etcd in enabled for GKE
deny contains msga if {
	cluster_config := input[_]
	cluster_config.apiVersion == "container.googleapis.com/v1"
	cluster_config.kind == "ClusterDescribe"
	cluster_config.metadata.provider == "gke"
	config := cluster_config.data

	not is_encrypted_GKE(config)

	msga := {
		"alertMessage": "etcd/secret encryption is not enabled",
		"alertScore": 3,
		"packagename": "armo_builtins",
		"reviewPaths": ["data.database_encryption.state"],
		"failedPaths": ["data.database_encryption.state"],
		"fixPaths": [],
		"fixCommand": "gcloud container clusters update <cluster_name> --region=<compute_region> --database-encryption-key=<key_project_id>/locations/<location>/keyRings/<ring_name>/cryptoKeys/<key_name> --project=<cluster_project_id>",
		"alertObject": {
			"k8sApiObjects": [],
			"externalObjects": cluster_config,
		},
	}
}

is_encrypted_GKE(config) if {
	config.database_encryption.state == "1"
}

is_encrypted_GKE(config) if {
	config.database_encryption.state == "ENCRYPTED"
}

is_encrypted_EKS(config) if {
	encryption := config.Cluster.EncryptionConfig[_]
	encryption.Provider.KeyArn != ""
	count(encryption.Resources) > 0
}

# Accept the camelCase shape too. kubescape's cloud collector normally
# feeds this rule the aws-sdk-go v2 DescribeClusterOutput struct which
# marshals to PascalCase (Cluster.EncryptionConfig). Environments that
# hand the raw AWS CLI / describe-cluster JSON (cluster.encryptionConfig)
# would otherwise always trip the C-0066 deny even with KMS actually
# enabled (kubescape/kubescape#1959).
is_encrypted_EKS(config) if {
	encryption := config.cluster.encryptionConfig[_]
	encryption.provider.keyArn != ""
	count(encryption.resources) > 0
}

isEncryptedAKS(cluster_config) if {
	profiles := cluster_config.properties.agentPoolProfiles
	count(profiles) > 0
	every p in profiles { p.enableEncryptionAtHost == true }
}

isEncryptedAKS(cluster_config) if {
	cluster_config.properties.securityProfile.azureKeyVaultKms.enabled == true
}

isEncryptedAKS(cluster_config) if {
	cluster_config.properties.securityProfile.kubernetesResourceObjectEncryptionProfile.infrastructureEncryption == "Enabled"
}

